      expectedOutput: 'Токенизация и стемминг:\n\nТекст: "The runners were running quickly..."\nТокены (nltk): [The, runners, were, running, quickly]\nТокены (regex): [The, runners, were, running, quickly]\n\nСтемминг (Porter): [the, runner, were, run, quickli]\nСтемминг (Snowball): [the, runner, were, run, quick]\nЛемматизация: [The, runner, be, running, quickly]',
      solution: 'import re\nimport nltk\nnltk.download("punkt", quiet=True)\nnltk.download("punkt_tab", quiet=True)\nnltk.download("wordnet", quiet=True)\nnltk.download("averaged_perceptron_tagger", quiet=True)\nnltk.download("averaged_perceptron_tagger_eng", quiet=True)\nfrom nltk.tokenize import word_tokenize, sent_tokenize\nfrom nltk.stem import PorterStemmer, SnowballStemmer\nfrom nltk.stem import WordNetLemmatizer\n\ntexts = [\n    "The runners were running quickly through the beautiful park.",\n    "She has been studying machine learning for better understanding of AI systems.",\n    "The children played happily while their dogs were chasing butterflies.",\n    "Dr. Smith\'s research papers on natural language processing are widely cited.",\n    "I can\'t believe how amazingly well the new algorithm performs on larger datasets!"\n]\n\nporter = PorterStemmer()\nsnowball = SnowballStemmer("english")\nlemmatizer = WordNetLemmatizer()\n\nprint("Токенизация и стемминг:\\n")\n\nfor i, text in enumerate(texts):\n    print(f"Текст {i+1}: \\\"{text}\\\"")\n\n    # NLTK токенизация\n    nltk_tokens = word_tokenize(text)\n    print(f"  Токены (nltk): {nltk_tokens}")\n\n    # Sentence tokenization\n    sentences = sent_tokenize(text)\n    print(f"  Предложения: {len(sentences)}")\n\n    # Regex токенизация\n    regex_tokens = re.findall(r"\\b\\w+\\b", text)\n    print(f"  Токены (regex): {regex_tokens}")\n\n    # Стемминг\n    porter_stems = [porter.stem(t) for t in nltk_tokens]\n    snowball_stems = [snowball.stem(t) for t in nltk_tokens]\n    print(f"  Porter: {porter_stems}")\n    print(f"  Snowball: {snowball_stems}")\n\n    # Лемматизация\n    lemmas = [lemmatizer.lemmatize(t) for t in nltk_tokens]\n    lemmas_verb = [lemmatizer.lemmatize(t, pos="v") for t in nltk_tokens]\n    print(f"  Лемма (noun): {lemmas}")\n    print(f"  Лемма (verb): {lemmas_verb}")\n    print()\n\n# Сравнение\nprint("Сравнение методов:")\ntest_words = ["running", "better", "studies", "happily", "children", "was", "mice"]\nprint(f"{\"Слово\":<15} {\"Porter\":<15} {\"Snowball\":<15} {\"Lemma(n)\":<15} {\"Lemma(v)\":<15}")\nprint("-" * 75)\nfor word in test_words:\n    p = porter.stem(word)\n    s = snowball.stem(word)\n    ln = lemmatizer.lemmatize(word)\n    lv = lemmatizer.lemmatize(word, pos="v")\n    print(f"{word:<15} {p:<15} {s:<15} {ln:<15} {lv:<15}")',
